import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient | undefined };

export const prisma = globalForPrisma.prisma ?? new PrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

import { jwtVerify } from "jose";
import type { NextRequest } from "next/server";

export interface AuthUser {
  userId: string;
  role: "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
  deptId: string;
}

function getSecret(): Uint8Array {
  return new TextEncoder().encode(
    process.env.AUTH_SECRET || "dev-secret-key-change-in-production"
  );
}

export class AuthError extends Error {
  constructor(
    message: string,
    public statusCode: number = 401
  ) {
    super(message);
    this.name = "AuthError";
  }
}

export async function verifyAuth(request: NextRequest): Promise<AuthUser> {
  const authHeader = request.headers.get("authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    throw new AuthError("Missing or invalid authorization header", 401);
  }
  const token = authHeader.slice(7);
  try {
    const { payload } = await jwtVerify(token, getSecret());
    const role = payload.role as string;
    if (!["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"].includes(role)) {
      throw new AuthError("Invalid role in token", 401);
    }
    return {
      userId: payload.sub as string,
      role: role as AuthUser["role"],
      deptId: payload.deptId as string,
    };
  } catch (e) {
    if (e instanceof AuthError) throw e;
    throw new AuthError("Invalid or expired token", 401);
  }
}

export function requireRole(
  user: AuthUser,
  ...roles: AuthUser["role"][]
): void {
  if (!roles.includes(user.role)) {
    throw new AuthError("Insufficient permissions", 403);
  }
}

export function requireOneOf(
  user: AuthUser,
  ...roles: AuthUser["role"][]
): void {
  if (!roles.includes(user.role)) {
    throw new AuthError("Insufficient permissions", 403);
  }
}

import type { Prisma, AssetInstanceStatus } from "@prisma/client";
import { AssetInstanceStatus as Status } from "@prisma/client";
import { prisma } from "./prisma";

export class AssetStateMachine {
  static allowedTransitions: Map<
    AssetInstanceStatus,
    AssetInstanceStatus[]
  > = new Map([
    [Status.IN_STOCK, [Status.AVAILABLE]],
    [Status.AVAILABLE, [Status.ASSIGNED, Status.LOST]],
    [
      Status.ASSIGNED,
      [Status.IN_USE, Status.AVAILABLE, Status.LOST],
    ],
    [
      Status.IN_USE,
      [
        Status.RETURNING,
        Status.REPAIRING,
        Status.TRANSFERRING,
        Status.LOST,
      ],
    ],
    [Status.RETURNING, [Status.AVAILABLE, Status.SCRAPPED]],
    [Status.REPAIRING, [Status.IN_USE, Status.AVAILABLE, Status.SCRAPPED]],
    [Status.TRANSFERRING, [Status.IN_USE]],
    [Status.LOST, []],
    [Status.SCRAPPED, []],
  ]);

  static canTransition(
    from: AssetInstanceStatus,
    to: AssetInstanceStatus
  ): boolean {
    const allowed = this.allowedTransitions.get(from);
    return allowed?.includes(to) ?? false;
  }

  /**
   * Execute an asset status transition within a transaction.
   * For LOST status, also auto-cancels all active tickets for the asset (§8.2.2).
   */
  static async transition(
    tx: Prisma.TransactionClient,
    assetId: string,
    to: AssetInstanceStatus,
    context: {
      operatorId: string;
      reason?: string;
      metadata?: Record<string, unknown>;
    }
  ) {
    const asset = await tx.assetInstance.findUniqueOrThrow({
      where: { id: assetId },
    });

    if (!this.canTransition(asset.status, to)) {
      throw new TransitionError(
        `Cannot transition asset ${assetId} from ${asset.status} to ${to}`
      );
    }

    const before = { status: asset.status, holderId: asset.holderId, deptId: asset.deptId };

    const updateData: Prisma.AssetInstanceUpdateInput = {
      status: to,
    };

    if (to === Status.LOST) {
      updateData.lostReason = context.reason || null;
    }
    if (to === Status.SCRAPPED) {
      updateData.scrapReason = context.reason || null;
      updateData.holderId = null;
    }
    if (to === Status.AVAILABLE) {
      updateData.holderId = null;
    }

    const updated = await tx.assetInstance.update({
      where: { id: assetId },
      data: updateData,
    });

    const after = { status: updated.status, holderId: updated.holderId, deptId: updated.deptId };

    // Handle lost: auto-cancel active tickets (§8.2.2)
    let cancelledTicketIds: string[] = [];
    if (to === Status.LOST) {
      const activeTickets = await tx.ticket.findMany({
        where: {
          targetAssetId: assetId,
          status: {
            notIn: ["COMPLETED", "CANCELLED", "REJECTED"] as any,
          },
        },
      });
      cancelledTicketIds = activeTickets.map((t) => t.id);
      if (activeTickets.length > 0) {
        await tx.ticket.updateMany({
          where: { id: { in: cancelledTicketIds } },
          data: { status: "CANCELLED" as any },
        });
      }
    }

    return { asset: updated, before, after, cancelledTicketIds };
  }
}

export class TransitionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "TransitionError";
  }
}

import type { Prisma, TicketType, TicketStatus } from "@prisma/client";
import { TicketStatus as Status, TicketType as Type } from "@prisma/client";
import { AssetStateMachine } from "./asset-state-machine";

export class TicketWorkflow {
  /**
   * Allowed status transitions per ticket type.
   * Key: TicketType -> Map<from, to[]>
   */
  static allowed: Map<
    TicketType,
    Map<TicketStatus, TicketStatus[]>
  > = new Map([
    [
      Type.APPLY,
      new Map([
        [Status.SUBMITTED, [Status.PENDING_MANAGER_1, Status.PENDING_IT, Status.CANCELLED]],
        [Status.PENDING_MANAGER_1, [Status.PENDING_IT, Status.REJECTED, Status.CANCELLED]],
        [Status.PENDING_IT, [Status.APPROVED, Status.REJECTED, Status.CANCELLED]],
        [Status.APPROVED, [Status.IN_PROGRESS, Status.CANCELLED]],
        [Status.IN_PROGRESS, [Status.COMPLETED]],
      ]),
    ],
    [
      Type.RETURN,
      new Map([
        [Status.SUBMITTED, [Status.PENDING_IT, Status.CANCELLED]],
        [Status.PENDING_IT, [Status.IN_PROGRESS, Status.REJECTED, Status.CANCELLED]],
        [Status.IN_PROGRESS, [Status.COMPLETED]],
      ]),
    ],
    [
      Type.REPAIR,
      new Map([
        [Status.SUBMITTED, [Status.PENDING_IT, Status.CANCELLED]],
        [Status.PENDING_IT, [Status.IN_PROGRESS, Status.REJECTED, Status.CANCELLED]],
        [Status.IN_PROGRESS, [Status.COMPLETED]],
      ]),
    ],
    [
      Type.TRANSFER,
      new Map([
        [Status.SUBMITTED, [Status.PENDING_MANAGER_1, Status.PENDING_MANAGER_2, Status.CANCELLED]],
        [Status.PENDING_MANAGER_1, [Status.PENDING_MANAGER_2, Status.REJECTED, Status.CANCELLED]],
        [Status.PENDING_MANAGER_2, [Status.PENDING_IT, Status.REJECTED, Status.CANCELLED]],
        [Status.PENDING_IT, [Status.IN_PROGRESS, Status.REJECTED, Status.CANCELLED]],
        [Status.IN_PROGRESS, [Status.COMPLETED]],
      ]),
    ],
  ]);

  static canTransition(
    type: TicketType,
    from: TicketStatus,
    to: TicketStatus
  ): boolean {
    return this.allowed.get(type)?.get(from)?.includes(to) ?? false;
  }

  /**
   * Determine the next status on approval for a ticket.
   */
  static nextOnApprove(
    type: TicketType,
    currentStatus: TicketStatus
  ): TicketStatus | null {
    switch (currentStatus) {
      case Status.PENDING_MANAGER_1:
        return type === Type.TRANSFER
          ? Status.PENDING_MANAGER_2
          : Status.PENDING_IT;
      case Status.PENDING_MANAGER_2:
        return Status.PENDING_IT;
      case Status.PENDING_IT:
        return type === Type.APPLY ? Status.APPROVED : Status.IN_PROGRESS;
      default:
        return null;
    }
  }

  /**
   * Determine initial status chain for a ticket based on business rules (§3.2, §4.2).
   * Returns the first target status after SUBMITTED.
   */
  static determineInitialStatus(
    type: TicketType,
    context: {
      purchasePrice?: number | null;
      applicantRole: string;
      applicantDeptId: string;
      deptManagerId: string | null;
      fromHolderId?: string | null;
    }
  ): TicketStatus {
    if (type === Type.RETURN || type === Type.REPAIR) {
      return Status.PENDING_IT;
    }

    if (type === Type.APPLY) {
      // Skip manager approval if price < 1000 (§3.2)
      if (context.purchasePrice != null && context.purchasePrice < 1000) {
        return Status.PENDING_IT;
      }
      // Skip if applicant is the department manager (self-approval check)
      if (
        context.applicantRole === "MANAGER" &&
        context.applicantDeptId != null
      ) {
        // MANAGER applying for themselves — skip to PENDING_IT
        // (The actual applicant vs manager check happens at approval time)
        return Status.PENDING_IT;
      }
      return Status.PENDING_MANAGER_1;
    }

    if (type === Type.TRANSFER) {
      // No fromHolderId means asset is available/in_stock — skip PENDING_MANAGER_1
      if (!context.fromHolderId) {
        return Status.PENDING_MANAGER_2;
      }
      return Status.PENDING_MANAGER_1;
    }

    return Status.PENDING_IT;
  }

  /**
   * Get the target status for an approve action based on current ticket state.
   */
  static getApproveTarget(
    type: TicketType,
    currentStatus: TicketStatus
  ): TicketStatus | null {
    return this.nextOnApprove(type, currentStatus);
  }

  /**
   * Execute a status transition with asset state changes.
   * Must be called within a Prisma transaction.
   */
  static async applyTransition(
    tx: Prisma.TransactionClient,
    ticketId: string,
    toStatus: TicketStatus,
    context: {
      operatorId: string;
      role: string;
      deptId: string;
      reason?: string;
      deputy?: boolean;
      metadata?: Record<string, unknown>;
    }
  ) {
    const ticket = await tx.ticket.findUniqueOrThrow({
      where: { id: ticketId },
      include: { targetAsset: true },
    });

    if (!this.canTransition(ticket.type, ticket.status, toStatus)) {
      throw new WorkflowError(
        `Cannot transition ticket ${ticketId} from ${ticket.status} to ${toStatus}`
      );
    }

    const beforeStatus = ticket.status;

    const updateData: Prisma.TicketUpdateInput = {
      status: toStatus,
    };

    if (toStatus === Status.REJECTED && context.reason) {
      updateData.rejectReason = context.reason;
    }
    if (toStatus === Status.COMPLETED) {
      updateData.completedAt = new Date();
    }
    if (context.deputy) {
      updateData.deputyApproval = true;
      updateData.deputyApproverId = context.operatorId;
    }

    const updated = await tx.ticket.update({
      where: { id: ticketId },
      data: updateData,
    });

    // Handle asset state changes tied to ticket transitions
    let assetChanges: { before: any; after: any } | null = null;

    if (ticket.targetAsset && toStatus === Status.IN_PROGRESS && ticket.type === Type.RETURN) {
      // RETURN: IT processing the return — asset already in RETURNING from creation
    }

    if (toStatus === Status.COMPLETED) {
      if (ticket.targetAsset) {
        let targetStatus: string | null = null;
        if (ticket.type === Type.APPLY) {
          targetStatus = "IN_USE";
        } else if (ticket.type === Type.RETURN) {
          targetStatus = "AVAILABLE";
        }

        if (targetStatus) {
          const assetBefore = {
            status: ticket.targetAsset.status,
            holderId: ticket.targetAsset.holderId,
          };
          const assetAfter = await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: {
              status: targetStatus as any,
              ...(targetStatus === "AVAILABLE" ? { holderId: null } : {}),
              ...(targetStatus === "IN_USE" && ticket.applicantId
                ? { holderId: ticket.applicantId, deptId: context.deptId }
                : {}),
            },
          });
          assetChanges = {
            before: assetBefore,
            after: {
              status: assetAfter.status,
              holderId: assetAfter.holderId,
            },
          };
        }
      }
    }

    return { ticket: updated, beforeStatus, afterStatus: toStatus, assetChanges };
  }
}

export class WorkflowError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "WorkflowError";
  }
}

import type { Prisma } from "@prisma/client";

export interface CreateAuditLogParams {
  action: string;
  operatorId: string;
  targetType: string;
  targetId: string;
  beforeSnapshot?: Record<string, unknown> | null;
  afterSnapshot?: Record<string, unknown> | null;
  metadata?: Record<string, unknown> | null;
}

export async function createAuditLog(
  tx: Prisma.TransactionClient,
  params: CreateAuditLogParams
) {
  return tx.auditLog.create({
    data: {
      action: params.action,
      operatorId: params.operatorId,
      targetType: params.targetType,
      targetId: params.targetId,
      beforeSnapshot: (params.beforeSnapshot as any) ?? undefined,
      afterSnapshot: (params.afterSnapshot as any) ?? undefined,
      metadata: (params.metadata as any) ?? undefined,
    },
  });
}

/**
 * Quick helper to log an asset status change.
 */
export async function logAssetStatusChange(
  tx: Prisma.TransactionClient,
  params: {
    assetId: string;
    operatorId: string;
    fromStatus: string;
    toStatus: string;
    metadata?: Record<string, unknown>;
  }
) {
  return createAuditLog(tx, {
    action: "asset.status_change",
    operatorId: params.operatorId,
    targetType: "asset",
    targetId: params.assetId,
    beforeSnapshot: { status: params.fromStatus },
    afterSnapshot: { status: params.toStatus },
    metadata: params.metadata,
  });
}

/**
 * Quick helper to log a ticket status change.
 */
export async function logTicketStatusChange(
  tx: Prisma.TransactionClient,
  params: {
    ticketId: string;
    operatorId: string;
    fromStatus: string;
    toStatus: string;
    metadata?: Record<string, unknown>;
  }
) {
  return createAuditLog(tx, {
    action: "ticket.status_change",
    operatorId: params.operatorId,
    targetType: "ticket",
    targetId: params.ticketId,
    beforeSnapshot: { status: params.fromStatus },
    afterSnapshot: { status: params.toStatus },
    metadata: params.metadata,
  });
}

import type { AssetModel, AssetInstance } from "@prisma/client";

type Role = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";

/**
 * Sanitize an AssetModel based on role (§5.2).
 * - EMPLOYEE/MANAGER: strip purchasePrice, supplier
 * - IT_ADMIN: full access
 * - EXECUTIVE: strip supplier, purchasePrice only in aggregate
 */
export function sanitizeAssetModel(
  model: AssetModel,
  role: Role
): Record<string, unknown> {
  const base: Record<string, unknown> = {
    id: model.id,
    category: model.category,
    brandName: model.brandName,
    modelName: model.modelName,
    specs: model.specs,
    warrantyMonths: model.warrantyMonths,
    status: model.status,
  };

  if (role === "IT_ADMIN") {
    return {
      ...base,
      purchasePrice: model.purchasePrice,
      supplier: model.supplier,
    };
  }

  if (role === "EXECUTIVE") {
    // EXECUTIVE: don't return purchasePrice per-item, only aggregate
    return {
      ...base,
      // no purchasePrice, no supplier, no sn
    };
  }

  // EMPLOYEE / MANAGER: strip price and supplier
  return base;
}

/**
 * Sanitize an AssetInstance based on role (§5.2).
 * - EMPLOYEE/MANAGER: strip purchasePrice, supplier, sn
 *   - MANAGER can see own department's assets
 *   - EMPLOYEE can only see their own
 * - IT_ADMIN: full access
 * - EXECUTIVE: strip supplier, sn; only aggregate data (not individual)
 */
export function sanitizeAssetInstance(
  instance: AssetInstance & { model?: AssetModel },
  role: Role
): Record<string, unknown> {
  const base: Record<string, unknown> = {
    id: instance.id,
    status: instance.status,
    holderId: instance.holderId,
    deptId: instance.deptId,
    purchaseDate: instance.purchaseDate,
    warrantyExpiry: instance.warrantyExpiry,
    createdAt: instance.createdAt,
    updatedAt: instance.updatedAt,
  };

  if (instance.model) {
    Object.assign(base, { model: sanitizeAssetModel(instance.model, role) });
  }

  if (role === "IT_ADMIN") {
    return {
      ...base,
      sn: instance.sn,
    };
  }

  // EMPLOYEE/MANAGER/EXECUTIVE: strip sn
  return base;
}

import type { Prisma } from "@prisma/client";

type NotificationType =
  | "APPROVAL_REQUEST"
  | "APPROVAL_RESULT"
  | "PICKUP_READY"
  | "REPAIR_UPDATE"
  | "WARRANTY_EXPIRY"
  | "TRANSFER_REQUEST"
  | "RETURN_SUBMITTED";

/**
 * Create a notification for a user.
 */
export async function createNotification(
  tx: Prisma.TransactionClient,
  params: {
    userId: string;
    type: NotificationType;
    title: string;
    body: string;
    relatedTicketId?: string;
    relatedAssetId?: string;
  }
) {
  return tx.notification.create({
    data: {
      userId: params.userId,
      type: params.type as any,
      title: params.title,
      body: params.body,
      relatedTicketId: params.relatedTicketId ?? null,
      relatedAssetId: params.relatedAssetId ?? null,
    },
  });
}

/**
 * Notify the department manager about a pending approval.
 */
export async function notifyApprovalRequest(
  tx: Prisma.TransactionClient,
  params: {
    managerId: string;
    ticketId: string;
    applicantName: string;
    ticketType: string;
  }
) {
  return createNotification(tx, {
    userId: params.managerId,
    type: "APPROVAL_REQUEST",
    title: "新审批请求",
    body: `${params.applicantName} 提交了${ticketTypeName(params.ticketType)}申请，请审批。`,
    relatedTicketId: params.ticketId,
  });
}

/**
 * Notify the applicant about approval result.
 */
export async function notifyApprovalResult(
  tx: Prisma.TransactionClient,
  params: {
    applicantId: string;
    ticketId: string;
    approved: boolean;
    ticketType: string;
  }
) {
  return createNotification(tx, {
    userId: params.applicantId,
    type: "APPROVAL_RESULT",
    title: params.approved ? "审批通过" : "审批驳回",
    body: `您的${ticketTypeName(params.ticketType)}申请已${params.approved ? "通过" : "被驳回"}。`,
    relatedTicketId: params.ticketId,
  });
}

function ticketTypeName(type: string): string {
  const map: Record<string, string> = {
    APPLY: "申领",
    RETURN: "归还",
    REPAIR: "报修",
    TRANSFER: "调拨",
  };
  return map[type] || type;
}

