import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { createAuditLog, logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalRequest } from "@/lib/notifications";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = await request.json();
    const { modelId, reason } = body;

    if (!modelId || !reason) {
      return Response.json(
        { error: "modelId and reason are required" },
        { status: 400 }
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const model = await tx.assetModel.findUniqueOrThrow({
        where: { id: modelId },
      });

      if (model.status !== "ACTIVE") {
        throw new WorkflowError("Model is discontinued");
      }

      const dept = await tx.department.findUniqueOrThrow({
        where: { id: user.deptId },
      });

      const initialStatus = TicketWorkflow.determineInitialStatus(Type.APPLY, {
        purchasePrice: Number(model.purchasePrice),
        applicantRole: user.role,
        applicantDeptId: user.deptId,
        deptManagerId: dept.managerId,
      });

      const ticket = await tx.ticket.create({
        data: {
          type: "APPLY",
          status: initialStatus,
          applicantId: user.userId,
          targetModelId: modelId,
          reason,
        },
      });

      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: initialStatus,
        metadata: { modelId, purchasePrice: Number(model.purchasePrice) },
      });

      // Notify next approver
      if (initialStatus === "PENDING_MANAGER_1" && dept.managerId) {
        await notifyApprovalRequest(tx, {
          managerId: dept.managerId,
          ticketId: ticket.id,
          applicantName: user.userId,
          ticketType: "APPLY",
        });
      }

      return ticket;
    });

    return Response.json({ ticket: result }, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = await request.json();
    const { assetId, reason } = body;

    if (!assetId || !reason) {
      return Response.json(
        { error: "assetId and reason are required" },
        { status: 400 }
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.findUniqueOrThrow({
        where: { id: assetId },
      });

      // Must be the current holder
      if (asset.holderId !== user.userId) {
        throw new TransitionError("Asset is not yours to return");
      }

      // No active return ticket for this asset
      const activeReturn = await tx.ticket.findFirst({
        where: {
          targetAssetId: assetId,
          type: "RETURN",
          status: { notIn: ["COMPLETED", "CANCELLED", "REJECTED"] },
        },
      });
      if (activeReturn) {
        throw new TransitionError("An active return ticket already exists for this asset");
      }

      // Validate asset state transition
      if (!AssetStateMachine.canTransition(asset.status, "RETURNING")) {
        throw new TransitionError(
          `Cannot return asset in status ${asset.status}`
        );
      }

      // Update asset status
      const updatedAsset = await tx.assetInstance.update({
        where: { id: assetId },
        data: { status: "RETURNING" },
      });

      // Create ticket
      const ticket = await tx.ticket.create({
        data: {
          type: "RETURN",
          status: "PENDING_IT",
          applicantId: user.userId,
          targetAssetId: assetId,
          reason,
        },
      });

      // Audit logs
      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: asset.status,
        toStatus: "RETURNING",
      });
      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: "PENDING_IT",
      });

      return { ticket, asset: updatedAsset };
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof TransitionError || e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

