import { WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange, createAuditLog } from "@/lib/audit";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = await request.json();
    const { assetId, reason, aiTriageResult } = body;

    if (!assetId || !reason) {
      return Response.json(
        { error: "assetId and reason are required" },
        { status: 400 }
      );
    }

    // If aiTriageResult exists, check need_repair
    if (aiTriageResult) {
      if (aiTriageResult.needRepair === false) {
        return Response.json(
          {
            error: "AI assessment suggests this does not need repair",
            selfHelp: aiTriageResult.selfHelp || null,
          },
          { status: 400 }
        );
      }
    }

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.findUniqueOrThrow({
        where: { id: assetId },
        include: { model: true },
      });

      // Must be the current holder
      if (asset.holderId !== user.userId) {
        throw new TransitionError("Asset is not yours to submit for repair");
      }

      // Validate asset state transition
      if (!AssetStateMachine.canTransition(asset.status, "REPAIRING")) {
        throw new TransitionError(
          `Cannot submit asset in status ${asset.status} for repair`
        );
      }

      const updatedAsset = await tx.assetInstance.update({
        where: { id: assetId },
        data: { status: "REPAIRING" },
      });

      const triageToStore = aiTriageResult
        ? { category: aiTriageResult.category, severity: aiTriageResult.severity, needRepair: aiTriageResult.needRepair, reason: aiTriageResult.reason }
        : null;

      const ticket = await tx.ticket.create({
        data: {
          type: "REPAIR",
          status: "PENDING_IT",
          applicantId: user.userId,
          targetAssetId: assetId,
          reason,
          aiTriageResult: triageToStore,
        },
      });

      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: asset.status,
        toStatus: "REPAIRING",
        metadata: { aiTriageResult: !!aiTriageResult },
      });
      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: "PENDING_IT",
      });

      if (aiTriageResult) {
        await createAuditLog(tx, {
          action: "ai.triage",
          operatorId: user.userId,
          targetType: "ticket",
          targetId: ticket.id,
          metadata: {
            input: reason,
            output: aiTriageResult,
          },
        });
      }

      return { ticket, asset: updatedAsset };
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof TransitionError || e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalRequest } from "@/lib/notifications";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "IT_ADMIN");

    const body = await request.json();
    const { assetId, toHolderId, targetDeptId, reason } = body;

    if (!assetId || !toHolderId || !targetDeptId || !reason) {
      return Response.json(
        { error: "assetId, toHolderId, targetDeptId, and reason are required" },
        { status: 400 }
      );
    }

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.findUniqueOrThrow({
        where: { id: assetId },
        include: { holder: { include: { department: true } } },
      });

      // Asset must be in_use
      if (asset.status !== "IN_USE") {
        throw new TransitionError(
          `Cannot transfer asset in status ${asset.status}, must be in_use`
        );
      }

      // Validate transition
      if (!AssetStateMachine.canTransition(asset.status, "TRANSFERRING")) {
        throw new TransitionError(
          `Cannot transfer asset in status ${asset.status}`
        );
      }

      // Update asset status
      const updatedAsset = await tx.assetInstance.update({
        where: { id: assetId },
        data: { status: "TRANSFERRING" },
      });

      const fromHolderId = asset.holderId;

      const initialStatus = TicketWorkflow.determineInitialStatus(
        Type.TRANSFER,
        {
          purchasePrice: 0,
          applicantRole: user.role,
          applicantDeptId: user.deptId,
          deptManagerId: null,
          fromHolderId,
        }
      );

      const ticket = await tx.ticket.create({
        data: {
          type: "TRANSFER",
          status: initialStatus,
          applicantId: user.userId,
          targetAssetId: assetId,
          fromHolderId,
          toHolderId,
          targetDeptId,
          reason,
        },
      });

      await logAssetStatusChange(tx, {
        assetId,
        operatorId: user.userId,
        fromStatus: asset.status,
        toStatus: "TRANSFERRING",
      });
      await logTicketStatusChange(tx, {
        ticketId: ticket.id,
        operatorId: user.userId,
        fromStatus: "SUBMITTED",
        toStatus: initialStatus,
      });

      // Notify managers
      if (initialStatus === "PENDING_MANAGER_1" && asset.holder?.department?.managerId) {
        await notifyApprovalRequest(tx, {
          managerId: asset.holder.department.managerId,
          ticketId: ticket.id,
          applicantName: user.userId,
          ticketType: "TRANSFER",
        });
      }

      return { ticket, asset: updatedAsset };
    });

    return Response.json(result, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof TransitionError || e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

