import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
import { logTicketStatusChange } from "@/lib/audit";
import { notifyApprovalRequest, notifyApprovalResult } from "@/lib/notifications";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;
    const body = await request.json();
    const deputy = body.deputy === true;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: {
          applicant: { include: { department: true } },
          targetAsset: true,
        },
      });

      // Ticket must not be in terminal state
      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(ticket.status)) {
        throw new WorkflowError("Ticket is already in a terminal state");
      }

      // Determine who can approve
      const currentStatus = ticket.status;

      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
        if (deputy) {
          // Deputy approval: only IT_ADMIN can do this (§8.2.1)
          if (user.role !== "IT_ADMIN") {
            throw new WorkflowError("Only IT_ADMIN can perform deputy approval");
          }
        } else {
          // Regular manager approval
          if (user.role !== "MANAGER" && user.role !== "IT_ADMIN") {
            throw new WorkflowError("Only managers can approve");
          }
          // Manager must be from same department as applicant
          if (user.role === "MANAGER") {
            if (user.deptId !== ticket.applicant.deptId) {
              throw new WorkflowError("You can only approve tickets from your own department");
            }
            // Manager cannot approve their own tickets (§3.2)
            if (user.userId === ticket.applicantId) {
              throw new WorkflowError("Cannot approve your own ticket");
            }
          }
        }
      } else if (currentStatus === "PENDING_IT") {
        // IT approval: only IT_ADMIN
        if (user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only IT_ADMIN can approve at this stage");
        }
      } else {
        throw new WorkflowError(`Cannot approve ticket in status ${currentStatus}`);
      }

      const nextStatus = TicketWorkflow.nextOnApprove(ticket.type, currentStatus);
      if (!nextStatus) {
        throw new WorkflowError("No valid next status for approval");
      }

      const updateData: Record<string, unknown> = { status: nextStatus };
      if (deputy) {
        updateData.deputyApproval = true;
        updateData.deputyApproverId = user.userId;
      }

      // If RETURN type and moving to IN_PROGRESS, update asset if needed
      if (ticket.type === "RETURN" && nextStatus === "IN_PROGRESS" && ticket.targetAsset) {
        // Asset already in RETURNING state from creation
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: updateData as any,
      });

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: currentStatus,
        toStatus: nextStatus,
        metadata: {
          deputy,
          deputyOperatorId: deputy ? user.userId : undefined,
        },
      });

      // Notify applicant about approval
      await notifyApprovalResult(tx, {
        applicantId: ticket.applicantId,
        ticketId: id,
        approved: true,
        ticketType: ticket.type,
      });

      // If next is PENDING_IT and there's a manager approval before IT, notify IT
      if (nextStatus === "PENDING_IT") {
        const itAdmins = await tx.user.findMany({
          where: { role: "IT_ADMIN", status: "ACTIVE" },
        });
        for (const it of itAdmins) {
          await notifyApprovalRequest(tx, {
            managerId: it.id,
            ticketId: id,
            applicantName: ticket.applicant.name,
            ticketType: ticket.type,
          });
        }
      }

      return updated;
    });

    return Response.json({ ticket: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { logTicketStatusChange, logAssetStatusChange } from "@/lib/audit";
import { notifyApprovalResult } from "@/lib/notifications";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;
    const body = await request.json();
    const reason = body.reason || "No reason provided";

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: { applicant: true, targetAsset: true },
      });

      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(ticket.status)) {
        throw new WorkflowError("Ticket is already in a terminal state");
      }

      // Only allow rejection from pending states
      if (!["PENDING_MANAGER_1", "PENDING_MANAGER_2", "PENDING_IT"].includes(ticket.status)) {
        throw new WorkflowError(`Cannot reject ticket in status ${ticket.status}`);
      }

      // Determine if user has permission to reject
      const isPendingManager =
        ticket.status === "PENDING_MANAGER_1" || ticket.status === "PENDING_MANAGER_2";
      const isPendingIt = ticket.status === "PENDING_IT";

      if (isPendingManager) {
        // Managers can reject their department's tickets; IT_ADMIN can reject any
        if (user.role === "MANAGER") {
          if (user.deptId !== ticket.applicant.deptId) {
            throw new WorkflowError("You can only reject tickets from your own department");
          }
          if (user.userId === ticket.applicantId) {
            throw new WorkflowError("Cannot reject your own ticket");
          }
        } else if (user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only managers or IT_ADMIN can reject tickets");
        }
      } else if (isPendingIt && user.role !== "IT_ADMIN") {
        throw new WorkflowError("Only IT_ADMIN can reject at this stage");
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: { status: "REJECTED", rejectReason: reason },
      });

      // Restore asset status if applicable (§SM-05: reject doesn't change asset for simple cases)
      // For RETURN and REPAIR, revert asset status
      if (ticket.targetAsset) {
        if (ticket.type === "RETURN" && ticket.targetAsset.status === "RETURNING") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "IN_USE" },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "RETURNING",
            toStatus: "IN_USE",
            metadata: { reason: "Ticket rejected" },
          });
        } else if (ticket.type === "REPAIR" && ticket.targetAsset.status === "REPAIRING") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "IN_USE" },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "IN_USE",
            metadata: { reason: "Ticket rejected" },
          });
        }
      }

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: ticket.status,
        toStatus: "REJECTED",
        metadata: { rejectReason: reason },
      });

      await notifyApprovalResult(tx, {
        applicantId: ticket.applicantId,
        ticketId: id,
        approved: false,
        ticketType: ticket.type,
      });

      return updated;
    });

    return Response.json({ ticket: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { logTicketStatusChange, logAssetStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: { targetAsset: true },
      });

      // Only applicant or IT_ADMIN can cancel
      if (user.userId !== ticket.applicantId && user.role !== "IT_ADMIN") {
        throw new WorkflowError("Only the applicant or IT_ADMIN can cancel this ticket");
      }

      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(ticket.status)) {
        throw new WorkflowError("Ticket is already in a terminal state");
      }

      // Can only cancel before APPROVED/IN_PROGRESS (§4.2)
      if (!["SUBMITTED", "PENDING_MANAGER_1", "PENDING_MANAGER_2", "PENDING_IT"].includes(ticket.status)) {
        throw new WorkflowError(`Cannot cancel ticket in status ${ticket.status}`);
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: { status: "CANCELLED" },
      });

      // Restore asset status if applicable
      if (ticket.targetAsset) {
        if (ticket.targetAsset.status === "RETURNING") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "IN_USE" },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "RETURNING",
            toStatus: "IN_USE",
            metadata: { reason: "Ticket cancelled" },
          });
        } else if (ticket.targetAsset.status === "REPAIRING") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "IN_USE" },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "IN_USE",
            metadata: { reason: "Ticket cancelled" },
          });
        } else if (ticket.targetAsset.status === "TRANSFERRING") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "IN_USE" },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "TRANSFERRING",
            toStatus: "IN_USE",
            metadata: { reason: "Ticket cancelled" },
          });
        } else if (ticket.targetAsset.status === "ASSIGNED") {
          // For assigned assets that are cancelled (rejected pickup), revert to available
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "AVAILABLE", holderId: null },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "ASSIGNED",
            toStatus: "AVAILABLE",
            metadata: { reason: "Ticket cancelled" },
          });
        }
      }

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: ticket.status,
        toStatus: "CANCELLED",
        metadata: { cancelledBy: user.userId },
      });

      return updated;
    });

    return Response.json({ ticket: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can assign assets" }, { status: 403 });
    }

    const { id } = await params;
    const body = await request.json();
    const assetId: string | undefined = body.assetId;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: { targetModel: true },
      });

      if (ticket.status !== "APPROVED") {
        throw new WorkflowError(`Cannot assign asset to ticket in status ${ticket.status}`);
      }
      if (ticket.type !== "APPLY") {
        throw new WorkflowError("Only APPLY tickets can have assets assigned");
      }

      if (!assetId) {
        throw new WorkflowError("assetId is required");
      }

      const asset = await tx.assetInstance.findUniqueOrThrow({
        where: { id: assetId },
      });

      if (asset.status !== "AVAILABLE") {
        throw new WorkflowError(`Asset ${assetId} is not available (status: ${asset.status})`);
      }

      // Update ticket with assigned asset
      const updated = await tx.ticket.update({
        where: { id },
        data: {
          targetAssetId: assetId,
          assignedById: user.userId,
          status: "IN_PROGRESS",
        },
      });

      // Update asset status to assigned and set holder
      await tx.assetInstance.update({
        where: { id: assetId },
        data: {
          status: "ASSIGNED",
          holderId: ticket.applicantId,
          deptId: ticket.applicant.deptId,
        },
      });

