import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: { targetAsset: true, applicant: true },
      });

      if (ticket.status !== "IN_PROGRESS") {
        throw new WorkflowError(`Cannot confirm ticket in status ${ticket.status}`);
      }

      if (!["APPLY", "RETURN"].includes(ticket.type)) {
        throw new WorkflowError("Only APPLY and RETURN tickets can be confirmed via this endpoint");
      }

      // Permission checks
      if (ticket.type === "APPLY") {
        // Only the applicant or IT_ADMIN can confirm receipt
        if (user.userId !== ticket.applicantId && user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only the applicant or IT_ADMIN can confirm receipt");
        }
      } else if (ticket.type === "RETURN") {
        // Only IT_ADMIN can confirm return receipt
        if (user.role !== "IT_ADMIN") {
          throw new WorkflowError("Only IT_ADMIN can confirm return receipt");
        }
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: { status: "COMPLETED", completedAt: new Date() },
      });

      // Update asset status based on ticket type
      if (ticket.targetAsset) {
        if (ticket.type === "APPLY") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: {
              status: "IN_USE",
              holderId: ticket.applicantId,
              deptId: ticket.applicant.deptId,
            },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "ASSIGNED",
            toStatus: "IN_USE",
            metadata: { ticketId: id, action: "confirm_receipt" },
          });
        } else if (ticket.type === "RETURN") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "AVAILABLE", holderId: null },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "RETURNING",
            toStatus: "AVAILABLE",
            metadata: { ticketId: id, action: "confirm_return" },
          });
        }
      }

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: "IN_PROGRESS",
        toStatus: "COMPLETED",
      });

      return updated;
    });

    return Response.json({ ticket: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { WorkflowError } from "@/lib/ticket-workflow";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can complete repair tickets" }, { status: 403 });
    }

    const { id } = await params;
    const body = await request.json();
    const action: "return_holder" | "make_available" | "scrap" = body.action || "return_holder";

    const result = await prisma.$transaction(async (tx) => {
      const ticket = await tx.ticket.findUniqueOrThrow({
        where: { id },
        include: { targetAsset: true },
      });

      if (ticket.type !== "REPAIR") {
        throw new WorkflowError("Only REPAIR tickets can be completed via this endpoint");
      }
      if (ticket.status !== "IN_PROGRESS") {
        throw new WorkflowError(`Cannot complete ticket in status ${ticket.status}`);
      }

      const updated = await tx.ticket.update({
        where: { id },
        data: { status: "COMPLETED", completedAt: new Date() },
      });

      // Determine asset outcome (FN-07, FN-08)
      if (ticket.targetAsset) {
        if (action === "return_holder") {
          // Return to original holder
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: {
              status: "IN_USE",
              ...(ticket.fromHolderId ? { holderId: ticket.fromHolderId } : {}),
            },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "IN_USE",
            metadata: { ticketId: id, action: "return_holder" },
          });
        } else if (action === "make_available") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "AVAILABLE", holderId: null },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "AVAILABLE",
            metadata: { ticketId: id, action: "make_available" },
          });
        } else if (action === "scrap") {
          await tx.assetInstance.update({
            where: { id: ticket.targetAsset.id },
            data: { status: "SCRAPPED", holderId: null },
          });
          await logAssetStatusChange(tx, {
            assetId: ticket.targetAsset.id,
            operatorId: user.userId,
            fromStatus: "REPAIRING",
            toStatus: "SCRAPPED",
            metadata: { ticketId: id, action: "scrap" },
          });
        }
      }

      await logTicketStatusChange(tx, {
        ticketId: id,
        operatorId: user.userId,
        fromStatus: "IN_PROGRESS",
        toStatus: "COMPLETED",
        metadata: { repairAction: action },
      });

      return updated;
    });

    return Response.json({ ticket: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof WorkflowError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

