import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    const { searchParams } = new URL(request.url);
    const type = searchParams.get("type");
    const status = searchParams.get("status");
    const page = Math.max(1, parseInt(searchParams.get("page") || "1", 10));
    const limit = Math.min(50, Math.max(1, parseInt(searchParams.get("limit") || "20", 10)));
    const skip = (page - 1) * limit;

    const where: Record<string, unknown> = {
      applicantId: user.userId,
    };

    if (type) where.type = type;
    if (status) where.status = status;

    const [tickets, total] = await Promise.all([
      prisma.ticket.findMany({
        where: where as any,
        orderBy: { createdAt: "desc" },
        skip,
        take: limit,
        include: {
          targetAsset: { include: { model: true } },
          targetModel: true,
        },
      }),
      prisma.ticket.count({ where: where as any }),
    ]);

    return Response.json({
      tickets,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
    });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    const { id } = await params;

    const ticket = await prisma.ticket.findUnique({
      where: { id },
      include: {
        applicant: { select: { id: true, name: true, email: true, deptId: true } },
        targetAsset: { include: { model: true } },
        targetModel: true,
        assignedBy: { select: { id: true, name: true } },
        processor: { select: { id: true, name: true } },
        fromHolder: { select: { id: true, name: true } },
        toHolder: { select: { id: true, name: true } },
        deputyApprover: { select: { id: true, name: true } },
      },
    });

    if (!ticket) {
      return Response.json({ error: "Ticket not found" }, { status: 404 });
    }

    // Permission: applicant, their manager, IT_ADMIN, or EXECUTIVE can view
    const isApplicant = ticket.applicantId === user.userId;
    const isItAdmin = user.role === "IT_ADMIN";
    const isExecutive = user.role === "EXECUTIVE";

    if (!isApplicant && !isItAdmin && !isExecutive) {
      // Check if user is the manager of the applicant's department
      const dept = await prisma.department.findUnique({
        where: { id: ticket.applicant.deptId },
      });
      if (dept?.managerId !== user.userId) {
        return Response.json({ error: "Ticket not found" }, { status: 404 });
      }
    }

    // Get audit trail (timeline)
    const auditLogs = await prisma.auditLog.findMany({
      where: { targetType: "ticket", targetId: id },
      orderBy: { createdAt: "asc" },
      include: {
        operator: { select: { id: true, name: true } },
      },
    });

    return Response.json({ ticket, timeline: auditLogs });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

