import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(request: NextRequest) {
  try {
    const user = await verifyAuth(request);

    if (user.role === "MANAGER") {
      // Manager: tickets from their department pending manager approval
      const tickets = await prisma.ticket.findMany({
        where: {
          applicant: { deptId: user.deptId },
          applicantId: { not: user.userId }, // exclude own tickets
          status: { in: ["PENDING_MANAGER_1", "PENDING_MANAGER_2"] },
          OR: [
            { type: { not: "TRANSFER" } },
            {
              type: "TRANSFER",
              status: "PENDING_MANAGER_1",
              fromHolder: { deptId: user.deptId },
            },
          ],
        },
        orderBy: { createdAt: "desc" },
        include: {
          applicant: { select: { id: true, name: true, email: true } },
          targetAsset: { include: { model: true } },
          targetModel: true,
        },
      });

      return Response.json({ tickets });
    }

    if (user.role === "IT_ADMIN") {
      // IT Admin: tickets pending IT action
      const tickets = await prisma.ticket.findMany({
        where: { status: "PENDING_IT" },
        orderBy: { createdAt: "desc" },
        include: {
          applicant: { select: { id: true, name: true, email: true } },
          targetAsset: { include: { model: true } },
          targetModel: true,
        },
      });

      return Response.json({ tickets });
    }

    return Response.json({ error: "No pending approvals for your role" }, { status: 403 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

