import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can access this endpoint" }, { status: 403 });
    }

    const { id } = await params;

    const asset = await prisma.assetInstance.findUnique({
      where: { id },
      select: { id: true },
    });

    if (!asset) {
      return Response.json({ error: "Asset not found" }, { status: 404 });
    }

    const logs = await prisma.auditLog.findMany({
      where: { targetType: "asset", targetId: id },
      orderBy: { createdAt: "asc" },
      include: {
        operator: { select: { id: true, name: true } },
      },
    });

    return Response.json({ timeline: logs });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { AssetStateMachine } from "@/lib/asset-state-machine";
import { logAssetStatusChange } from "@/lib/audit";

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can inbound assets" }, { status: 403 });
    }

    const body = await request.json();
    const { id, sn, modelId, purchaseDate, warrantyMonths } = body;

    if (!id || !sn || !modelId || !purchaseDate) {
      return Response.json(
        { error: "id, sn, modelId, and purchaseDate are required" },
        { status: 400 }
      );
    }

    // Check uniqueness
    const existingId = await prisma.assetInstance.findUnique({ where: { id } });
    if (existingId) {
      return Response.json({ error: `Asset ID ${id} already exists` }, { status: 409 });
    }

    const existingSn = await prisma.assetInstance.findUnique({ where: { sn } });
    if (existingSn) {
      return Response.json({ error: `Serial number ${sn} already exists` }, { status: 409 });
    }

    // Validate model exists
    const model = await prisma.assetModel.findUniqueOrThrow({
      where: { id: modelId },
    });

    const warrantyMonthsNum = warrantyMonths ?? model.warrantyMonths;
    const purchaseDt = new Date(purchaseDate);
    const warrantyExpiry = new Date(purchaseDt);
    warrantyExpiry.setMonth(warrantyExpiry.getMonth() + warrantyMonthsNum);

    const result = await prisma.$transaction(async (tx) => {
      const asset = await tx.assetInstance.create({
        data: {
          id,
          sn,
          modelId,
          status: "IN_STOCK",
          purchaseDate: purchaseDt,
          warrantyExpiry,
        },
      });

      await logAssetStatusChange(tx, {
        assetId: id,
        operatorId: user.userId,
        fromStatus: "N/A",
        toStatus: "IN_STOCK",
        metadata: { action: "inbound" },
      });

      return asset;
    });

    return Response.json({ asset: result }, { status: 201 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can scrap assets" }, { status: 403 });
    }

    const { id } = await params;
    const body = await request.json();
    const reason = body.reason || "";

    const result = await prisma.$transaction(async (tx) => {
      const { asset, before, after } = await AssetStateMachine.transition(
        tx,
        id,
        "SCRAPPED" as any,
        { operatorId: user.userId, reason }
      );

      await logAssetStatusChange(tx, {
        assetId: id,
        operatorId: user.userId,
        fromStatus: before.status,
        toStatus: after.status,
        metadata: { scrapReason: reason },
      });

      return asset;
    });

    return Response.json({ asset: result });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await verifyAuth(request);
    if (user.role !== "IT_ADMIN") {
      return Response.json({ error: "Only IT_ADMIN can mark assets as lost" }, { status: 403 });
    }

    const { id } = await params;
    const body = await request.json();
    const reason = body.reason || "";

    const result = await prisma.$transaction(async (tx) => {
      const { asset, before, after, cancelledTicketIds } =
        await AssetStateMachine.transition(tx, id, "LOST" as any, {
          operatorId: user.userId,
          reason,
        });

      await logAssetStatusChange(tx, {
        assetId: id,
        operatorId: user.userId,
        fromStatus: before.status,
        toStatus: after.status,
        metadata: { lostReason: reason, cancelledTickets: cancelledTicketIds },
      });

      // Log each cancelled ticket (§8.2.2)
      for (const ticketId of cancelledTicketIds) {
        await logTicketStatusChange(tx, {
          ticketId,
          operatorId: user.userId,
          fromStatus: "ACTIVE",
          toStatus: "CANCELLED",
          metadata: { reason: "Asset marked as lost" },
        });
      }

      return { asset, cancelledTickets: cancelledTicketIds };
    });

    return Response.json(result);
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    if (e instanceof TransitionError) {
      return Response.json({ error: e.message }, { status: 400 });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

